SELECT * FROM training_record
WHERE user_id = #{userId} AND record_date BETWEEN #{startDate} AND #{endDate}
ORDER BY record_date DESC

SELECT record_date, training_type
FROM training_record
WHERE user_id = #{userId} AND YEAR(record_date) = #{year} AND MONTH(record_date) = #{month}

mapper.update:
UPDATE training_record SET training_type = #{trainingType}, start_time = #{startTime},
end_time = #{endTime}, duration_minutes = #{durationMinutes}, note = #{note}
WHERE id = #{id}
